// modules/tasks/module.contract.ts
import { defineContract } from 'aether';

export default defineContract({
  name: 'tasks',
  description: 'Handles task creation, retrieval, and deletion utilities.',

  dependencies: { modules: ['auth'] },

  exposes: {
    routes: [
      { method: 'POST', path: '/tasks', auth: true },
      { method: 'GET', path: '/tasks/:id', auth: true },
      { method: 'PUT', path: '/tasks/:id', auth: true },
      { method: 'DELETE', path: '/tasks/:id', auth: true }, // New route for soft-delete
    ],
    functions: ['createTask', 'getTask', 'updateTask', 'softDeleteTask'],
    types: ['Task', 'TaskError'],
  },

  sideEffects: [
    'writes to: tasks table',
    'reads from: users table',
  ],

  invariants: [
    'A task must always be associated with exactly one user',
    'Soft-deleted tasks must have a non-null deletedAt timestamp',
    'Deleting a task should invalidate any related sessions or notifications',
  ],
});

